SpotData={}local self=SpotData;local a=10000;function SpotData.Init(b)self.inActivity=b.showType==ESpotShowType.ActivitySpot;self.InitImageConfig()self.InitJsonData(b.data.content_path)self.InitBytesData(b.data.content_path)self.InitRecordData()end;function SpotData.GetJumpData(c)local d,e,b;local f=self.spots;if c<a then for g=1,#f do if f[g].spotid==c then d,e,b=g,1,f[g].SceneMap end end else for g=1,#f do for h=1,#f[g].SceneMap do if f[g].SceneMap[h].sceneId==c then d,e,b=g,h,f[g].SceneMap;break end end end end;return d,e,b end;function SpotData.InitImageConfig()if self.image_config then return end;self.image_config={}local i=Tools.Split(tostring(LuaTools.LoadText('docs/spots/pic_config.txt')),'\n')for g=1,#i do local j=Tools.Split(i[g],':')local k=Tools.Split(j[2],',')self.image_config[j[1]]={x=tonumber(k[1]),y=tonumber(k[2])}end end;function SpotData.InitJsonData(l)local m;if self.inActivity then local n=Tools.Split(l,"/")local o=n[#n]m='docs/spots/'..l..'/'..o..'.json'else m='docs/spots/'..l..'.json'end;self.jsonData=json.decode(tostring(LuaTools.LoadText(m)))self.spots=self.jsonData.Spots;local f=self.spots;local p=a;for g=1,#f do local q=f[g]local r=q.SceneMap;if q.endspotid>0 or q.rewardid>0 then local s={}r[#r].conditions=s;table.insert(s,{jumpId=q.endspotid,rewardId=q.rewardid,conditionStr=''})end;for h=1,#r do if not r[h].sceneId or r[h].sceneId<=0 then r[h].sceneId=p;p=p+1 end;if r[h].jump_id and r[h].jump_id>0 or r[h].reward_id and r[h].reward_id>0 then r[h].conditions={}table.insert(r[h].conditions,{jumpId=r[h].jump_id,rewardId=r[h].reward_id,conditionStr=''})end;if r[h]._background==''then r[h]._background='beijing_chunying'end;r[h]._background=string.gsub(r[h]._background,".jpg",'')end end end;function SpotData.InitBytesData(l)l=string.gsub(l,'.json','')local t;if self.inActivity then local n=Tools.Split(l,"/")local o=n[#n]t='docs/spots/'..l..'/'..o else t='docs/spots/'..l end;t=t..'_'..GameMgr.Inst.prefer_language..'.bytes'local u=tostring(LuaTools